const before = [
 {Kind:"method",Name:"C.F",Signature:"F()",BodyHash:"old-1",StartLine:1},
 {Kind:"method",Name:"C.F",Signature:"F()",BodyHash:"old-2",StartLine:5}
];
const after = [
 {Kind:"method",Name:"C.F",Signature:"F()",BodyHash:"new",StartLine:1},
 {Kind:"method",Name:"C.F",Signature:"F()",BodyHash:"old-1",StartLine:5},
 {Kind:"method",Name:"C.F",Signature:"F()",BodyHash:"old-2",StartLine:9}
];
const sigKey=e=>`${e.Kind}:${e.Name}:${e.Signature}`, base=e=>`${e.Kind}:${e.Name}`;
function counts(es){const m={}; for(const e of es)m[sigKey(e)]=(m[sigKey(e)]||0)+1; return m}
function keySide(es, other){const out={}, seen={}, leftovers={}; for(const e of es){const sk=sigKey(e), n=seen[sk]||0; seen[sk]=n+1;if(n<(other[sk]||0))out[`=${sk}#${n}`]=e;else{const b=base(e),i=leftovers[b]||0;out[`~${b}#${i}`]=e;leftovers[b]=i+1;}}return out}
const b=keySide(before,counts(after)),a=keySide(after,counts(before));
const events=[];
for(const [k,e] of Object.entries(b)){if(!a[k])events.push(["removed",e.BodyHash]);else if(a[k].BodyHash!==e.BodyHash)events.push(["body_changed",e.BodyHash,a[k].BodyHash]);}
for(const [k,e] of Object.entries(a)){if(!b[k])events.push(["added",e.BodyHash]);}
text(JSON.stringify({beforeKeys:b,afterKeys:a,events},null,2));

